import java.util.HashMap;
import java.util.Map;

public int maximumChemistry(int[] skill) {
    int total_sum = 0;
    for (int s : skill) {
        total_sum += s;
    }
    int target_sum = total_sum / 2;
    if (total_sum % 2 == 1) return -1;

    Map<Integer, Integer> dp = new HashMap<>();
    dp.put(0, 1);
    int max_chemistry = 0;

    for (int s : skill) {
        for (int i = target_sum - s; i >= 0; i--) {
            if (dp.containsKey(i)) {
                dp.put(i + s, dp.getOrDefault(i + s, 0) + dp.get(i));
                if (i + s == target_sum) {
                    max_chemistry += dp.get(i) * s;
                }
            }
        }
    }

    return (max_chemistry > 0) ? max_chemistry : -1;
}
